import React, { useEffect, useState } from 'react';
import {
    Box,
    Grid,
    Card,
    CardContent,
    Typography,
    Button
} from '@mui/material';
import {
    People,
    Assignment,
    LocationOn,
    TrendingUp
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

const StatCard = ({ title, value, icon }) => (
    <Card sx={{ borderRadius: 3 }}>
        <CardContent>
            <Box display="flex" justifyContent="space-between">
                <Box>
                    <Typography variant="subtitle2">{title}</Typography>
                    <Typography variant="h5" fontWeight="bold">
                        {value}
                    </Typography>
                </Box>
                {icon}
            </Box>
        </CardContent>
    </Card>
);

const AdminDashboard = () => {
    const navigate = useNavigate();

    const [stats, setStats] = useState({
        totalEmployees: 0,
        todayPunches: 0,
        pendingApprovals: 0,
        totalDistance: 0,
    });

    useEffect(() => {
        loadDashboard();
    }, []);

    const loadDashboard = async () => {
        try {
            const res = await api.getDashboardStats();
            setStats(res.data);
        } catch (err) {
            console.error(err);
        }
    };

    return (
        <Box sx={{ p: 2 }}>

            {/* ================= HEADER ================= */}
            <Typography variant="h5" fontWeight="bold" mb={2}>
                Admin Dashboard
            </Typography>

            {/* ================= KPI ================= */}
            <Grid container spacing={2}>
                <Grid item xs={12} md={3}>
                    <StatCard
                        title="Total Employees"
                        value={stats.totalEmployees}
                        icon={<People color="primary" />}
                    />
                </Grid>

                <Grid item xs={12} md={3}>
                    <StatCard
                        title="Today Punches"
                        value={stats.todayPunches}
                        icon={<Assignment color="secondary" />}
                    />
                </Grid>

                <Grid item xs={12} md={3}>
                    <StatCard
                        title="Pending Approvals"
                        value={stats.pendingApprovals}
                        icon={<TrendingUp color="error" />}
                    />
                </Grid>

                <Grid item xs={12} md={3}>
                    <StatCard
                        title="Distance Today (KM)"
                        value={stats.totalDistance}
                        icon={<LocationOn color="success" />}
                    />
                </Grid>
            </Grid>

            {/* ================= QUICK ACTIONS ================= */}
            <Box mt={4}>
                <Typography variant="h6" mb={2}>
                    Quick Actions
                </Typography>

                <Grid container spacing={2}>
                    <Grid item>
                        <Button
                            variant="contained"
                            onClick={() => navigate('/admin/create-user')}
                        >
                            ➕ Create User
                        </Button>
                    </Grid>

                    <Grid item>
                        <Button
                            variant="outlined"
                            onClick={() => navigate('/admin/users')}
                        >
                            👥 View Users
                        </Button>
                    </Grid>

                    <Grid item>
                        <Button
                            variant="outlined"
                            onClick={() => navigate('/admin/employee-tracking')}
                        >
                            📍 Employee Tracking
                        </Button>
                    </Grid>
                </Grid>
            </Box>

            {/* ================= ANALYTICS ================= */}
            <Box mt={5}>
                <Typography variant="h6" mb={2}>
                    Analytics (Coming Soon)
                </Typography>

                <Card sx={{ p: 3 }}>
                    <Typography>
                        📊 Future analytics:
                    </Typography>
                    <ul>
                        <li>Daily attendance trends</li>
                        <li>Top performing employees</li>
                        <li>Inactive employees</li>
                        <li>Location heatmap</li>
                    </ul>
                </Card>
            </Box>

            {/* ================= RECENT ACTIVITY ================= */}
            <Box mt={5}>
                <Typography variant="h6" mb={2}>
                    Recent Activity
                </Typography>

                <Card sx={{ p: 3 }}>
                    <Typography>
                        🔄 You can show:
                    </Typography>
                    <ul>
                        <li>Latest punches</li>
                        <li>Recent approvals</li>
                        <li>New users created</li>
                    </ul>
                </Card>
            </Box>
        </Box>
    );
};

export default AdminDashboard;